import {
  ref, get, set, update, push, onValue, remove
} from 'firebase/database';
import {
  signInWithEmailAndPassword, signOut, createUserWithEmailAndPassword
} from 'firebase/auth';
import { db, auth } from './config';

// ─── AUTH ───────────────────────────────────────────────────────────────────

export const loginPlayer = (email, password) =>
  signInWithEmailAndPassword(auth, email, password);

export const logoutPlayer = () => signOut(auth);

export const createPlayerAuth = (email, password) =>
  createUserWithEmailAndPassword(auth, email, password);

// ─── PLAYERS ────────────────────────────────────────────────────────────────

export const getPlayers = async () => {
  const snap = await get(ref(db, 'players'));
  if (!snap.exists()) return [];
  const data = snap.val();
  return Object.entries(data).map(([id, val]) => ({ id, ...val }));
};

export const getPlayer = async (uid) => {
  const snap = await get(ref(db, `players/${uid}`));
  return snap.exists() ? { id: uid, ...snap.val() } : null;
};

export const createPlayer = async (uid, data) => {
  await set(ref(db, `players/${uid}`), {
    ...data,
    hasWon: false,
    wonMonth: null,
    createdAt: Date.now()
  });
};

export const listenPlayers = (callback) => {
  const playersRef = ref(db, 'players');
  const unsub = onValue(playersRef, (snap) => {
    if (!snap.exists()) { callback([]); return; }
    const data = snap.val();
    callback(Object.entries(data).map(([id, val]) => ({ id, ...val })));
  });
  return unsub;
};

// ─── GROUP SETTINGS ─────────────────────────────────────────────────────────

export const getGroupSettings = async () => {
  const snap = await get(ref(db, 'settings/group'));
  return snap.exists() ? snap.val() : null;
};

export const setGroupSettings = async (data) => {
  await set(ref(db, 'settings/group'), data);
};

export const listenGroupSettings = (callback) => {
  const unsub = onValue(ref(db, 'settings/group'), (snap) => {
    callback(snap.exists() ? snap.val() : null);
  });
  return unsub;
};

// ─── AUCTION ────────────────────────────────────────────────────────────────

export const getCurrentAuction = async () => {
  const snap = await get(ref(db, 'auction/current'));
  return snap.exists() ? snap.val() : null;
};

export const listenAuction = (callback) => {
  const unsub = onValue(ref(db, 'auction/current'), (snap) => {
    callback(snap.exists() ? snap.val() : null);
  });
  return unsub;
};

export const startAuction = async (settings, isLastPlayer = false) => {
  const { monthlyAmount, totalPlayers } = settings;
  const minBid = Math.floor(monthlyAmount * 0.1);
  const totalPool = monthlyAmount * totalPlayers;
  const endsAt = new Date(Date.now() + 15 * 60 * 1000).toISOString();

  await set(ref(db, 'auction/current'), {
    active: true,
    isLastPlayer,
    month: new Date().toISOString().slice(0, 7),
    startedAt: Date.now(),
    endsAt,
    currentBid: minBid,
    currentBidder: null,
    currentBidderName: null,
    minBid,
    totalPool,
    monthlyAmount,
    totalPlayers,
    bids: {},
    closed: false
  });
};

export const placeBid = async (uid, playerName, amount) => {
  const auctionSnap = await get(ref(db, 'auction/current'));
  if (!auctionSnap.exists()) throw new Error('No active auction');
  const data = auctionSnap.val();

  if (!data.active || data.closed) throw new Error('Auction is not active');
  if (amount <= data.currentBid) throw new Error(`Bid must be more than ₹${data.currentBid}`);
  if (new Date() > new Date(data.endsAt)) throw new Error('Auction time has ended');
  if (data.currentBidder === uid) throw new Error("You're already the highest bidder!");

  const bidKey = Date.now().toString();
  const updates = {
    'auction/current/currentBid': amount,
    'auction/current/currentBidder': uid,
    'auction/current/currentBidderName': playerName,
    [`auction/current/bids/${bidKey}`]: {
      uid,
      playerName,
      amount,
      timestamp: new Date().toISOString()
    }
  };
  await update(ref(db), updates);
};

export const closeAuction = async () => {
  const auctionSnap = await get(ref(db, 'auction/current'));
  if (!auctionSnap.exists()) throw new Error('No auction found');
  const data = auctionSnap.val();

  const bidsArray = data.bids
    ? Object.values(data.bids).sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp))
    : [];

  let winnerReceives, perPlayerBonus, winningBid, winnerId, winnerName;

  if (data.isLastPlayer) {
    // Last player: no auction needed, gets totalPool and monthly contributions distributed
    winningBid = 0;
    winnerReceives = data.totalPool;
    perPlayerBonus = data.monthlyAmount;
    winnerId = data.currentBidder;
    winnerName = data.currentBidderName;
  } else {
    winningBid = data.currentBid;
    winnerReceives = data.totalPool - winningBid;
    perPlayerBonus = Math.floor(winningBid / data.totalPlayers);
    winnerId = data.currentBidder;
    winnerName = data.currentBidderName;
  }

  const result = {
    month: data.month,
    winnerId,
    winnerName,
    winningBid,
    winnerReceives,
    perPlayerBonus,
    totalPool: data.totalPool,
    bids: bidsArray,
    isLastPlayer: data.isLastPlayer || false,
    closedAt: new Date().toISOString()
  };

  // Save to records
  const recordKey = `${data.month}-${Date.now()}`;
  const updates = {
    [`records/${recordKey}`]: result,
    'auction/current/active': false,
    'auction/current/closed': true,
    'auction/current/result': result
  };

  // Mark winner as won
  if (winnerId) {
    updates[`players/${winnerId}/hasWon`] = true;
    updates[`players/${winnerId}/wonMonth`] = data.month;
  }

  await update(ref(db), updates);
  return result;
};

// ─── RECORDS ────────────────────────────────────────────────────────────────

export const getRecords = async () => {
  const snap = await get(ref(db, 'records'));
  if (!snap.exists()) return [];
  return Object.entries(snap.val())
    .map(([id, val]) => ({ id, ...val }))
    .sort((a, b) => new Date(b.closedAt) - new Date(a.closedAt));
};

export const listenRecords = (callback) => {
  const unsub = onValue(ref(db, 'records'), (snap) => {
    if (!snap.exists()) { callback([]); return; }
    const records = Object.entries(snap.val())
      .map(([id, val]) => ({ id, ...val }))
      .sort((a, b) => new Date(b.closedAt) - new Date(a.closedAt));
    callback(records);
  });
  return unsub;
};

// ─── RESET (Admin only) ─────────────────────────────────────────────────────

export const resetAllWins = async () => {
  const players = await getPlayers();
  const updates = {};
  players.forEach(p => {
    updates[`players/${p.id}/hasWon`] = false;
    updates[`players/${p.id}/wonMonth`] = null;
  });
  await update(ref(db), updates);
};
